metadata.codeSnippet:
import { callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const userQuery = "For this Polymarket market, what exactly makes it resolve YES or NO, what source settles it, and what edge-case gotchas could surprise traders?";

  const executionPlan = {
    strictValidation: true,
    semanticIntentSatisfied: false,
    intent: {
      requiresDirectInstrument: true,
      requiresCrossVenueCoverage: false,
      requiresPortfolioConstruction: false,
      requiresHedge: false,
      requiresRepresentativeOutcomeSelection: false,
      requiresBinaryEfficiencyPath: false
    },
    phases: [
      {
        name: "probe",
        goal: "Resolve the exact Polymarket market from the user's context before any rules lookup.",
        parallelReadOnlyCalls: [
          {
            toolName: "search_markets",
            args: { query: userQuery, status: "live", limit: 10 }
          },
          {
            toolName: "search_and_get_outcomes",
            args: { query: userQuery }
          }
        ],
        note: "Parallelism is only across different tools/endpoints; no same-endpoint Promise.all fan-out."
      },
      {
        name: "decide",
        goal: "Use deterministic semantic targeting to choose the intended market if discovery returns multiple candidates.",
        method: "pickTopSemanticCandidates",
        rankingInputs: {
          target: userQuery,
          requiredTerms: ["Polymarket", "market", "resolve", "YES", "NO"],
          avoidTerms: ["unrelated", "proxy", "different event", "broad category"],
          limit: 1
        },
        decisionRule: "Prefer the highest-confidence candidate whose title/query alignment best matches the user's implied single market."
      },
      {
        name: "execute",
        goal: "Fetch market-specific resolution rules, settlement source, and edge-case gotchas for the resolved instrument.",
        sequentialCalls: [
          {
            toolName: "check_market_rules",
            args: { slug: "<resolved-slug>" }
          }
        ],
        note: "Only run after the probe/decide stages confirm the intended market."
      }
    ],
    fallbackPolicy: {
      bounded: true,
      maxAlternateBranches: 2,
      ifNoClearMatch: {
        returnStructuredGaps: ["resolvedMarket", "slug", "conditionId"],
        attemptedBranches: ["search_markets", "search_and_get_outcomes"],
        stopReason: "ambiguous_market_identity"
      }
    },
    localAnalysisAfterReadBatch: {
      serialOnly: true,
      tasks: [
        "Compare discovery candidates and select one deterministic match",
        "Extract resolvesYesIf, resolvesNoIf, resolutionSource, ambiguities, and potentialGotchas",
        "Package the final response with the exact market title and any caution flags"
      ]
    }
  };

  return {
    userQuery,
    executionPlan,
    readyToExecute: true
  };
}

