import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "summarize_live_market_activity",
    args: {
      sortBy: "ending_soon",
      endingWithinDays: 7,
      tradeLimit: 20
    }
  });

  const selectedMarket = result?.selectedMarket || {};
  const tradesSummary = result?.tradesSummary || {};
  const openInterest = result?.openInterest || {};
  const recentTrades = Array.isArray(result?.recentTrades) ? result.recentTrades : [];

  const buyVolume = typeof tradesSummary.buyVolume === "number" ? tradesSummary.buyVolume : 0;
  const sellVolume = typeof tradesSummary.sellVolume === "number" ? tradesSummary.sellVolume : 0;
  const totalVolume = typeof tradesSummary.totalVolume === "number" ? tradesSummary.totalVolume : 0;
  const oiValue = typeof openInterest.value === "number" ? openInterest.value : 0;

  const buySellImbalance = totalVolume > 0 ? (buyVolume - sellVolume) / totalVolume : 0;
  const oiToVolume = totalVolume > 0 ? oiValue / totalVolume : null;

  let tapeRead = "indeterminate";
  if (totalVolume === 0 || oiValue === 0) {
    tapeRead = "insufficient data";
  } else if (oiToVolume !== null && oiToVolume >= 2 && Math.abs(buySellImbalance) >= 0.15) {
    tapeRead = "fresh conviction";
  } else if (oiToVolume !== null && oiToVolume < 1 && Math.abs(buySellImbalance) < 0.15) {
    tapeRead = "churn";
  } else if (oiToVolume !== null && oiToVolume >= 1.5 && Math.abs(buySellImbalance) < 0.1) {
    tapeRead = "mixed, leaning churn";
  } else {
    tapeRead = "mixed, leaning fresh conviction";
  }

  return {
    selectedMarket,
    activity: {
      tradesSummary,
      openInterest
    },
    recentTradesSample: recentTrades.slice(0, 5),
    derivedRead: {
      tapeRead,
      buySellImbalance,
      oiToVolume
    }
  };
}

